'use client';

import { useState, useRef } from 'react';
import { useAuth } from '../../contexts/AuthContext';
import { updateUser } from '../../utils/storage';
import { Button } from '../ui/button';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '../ui/card';
import { Input } from '../ui/input';
import { Label } from '../ui/label';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '../ui/select';
import { ArrowLeft, Camera, Save, User as UserIcon } from 'lucide-react';
import { toast } from 'sonner';

interface ProfilePageProps {
  onBack: () => void;
}

export default function ProfilePage({ onBack }: ProfilePageProps) {
  const { user, updateCurrentUser } = useAuth();
  const [formData, setFormData] = useState({
    name: user?.name || '',
    email: user?.email || '',
    program: user?.program || '',
    year: user?.year || 1,
    profilePic: user?.profilePic || ''
  });
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64String = reader.result as string;
        setFormData({ ...formData, profilePic: base64String });
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSave = () => {
    if (!user) return;

    const updates = {
      name: formData.name,
      email: formData.email,
      ...(user.role === 'student' && {
        program: formData.program,
        year: formData.year
      }),
      profilePic: formData.profilePic
    };

    updateUser(user.id, updates);
    updateCurrentUser(updates);
    toast.success('Profile updated successfully!');
  };

  return (
    <div className="min-h-screen bg-gray-50 pb-12">
      <header className="bg-white border-b sticky top-0 z-10">
        <div className="container mx-auto px-4 py-4">
          <Button variant="ghost" onClick={onBack}>
            <ArrowLeft className="w-4 h-4 mr-2" />
            Back
          </Button>
        </div>
      </header>

      <main className="container mx-auto px-4 py-8 max-w-3xl">
        <Card className="overflow-hidden border-primary/10 shadow-lg">
          {/* Landscape Hero Header */}
          <div className="h-48 bg-primary relative">
            <div className="absolute inset-0 bg-black/10" />
            <div className="absolute -bottom-16 left-8 flex items-end gap-6">
              <div className="relative group">
                <div className="w-32 h-32 rounded-full border-4 border-white bg-accent flex items-center justify-center overflow-hidden shadow-xl">
                  {formData.profilePic ? (
                    <img 
                      src={formData.profilePic} 
                      alt="Profile"
                      className="w-full h-full object-cover"
                    />
                  ) : (
                    <UserIcon className="w-16 h-16 text-primary" />
                  )}
                </div>
                <button
                  type="button"
                  onClick={() => fileInputRef.current?.click()}
                  className="absolute bottom-1 right-1 p-2 rounded-full bg-primary text-white hover:bg-primary/90 shadow-lg border-2 border-white transition-transform active:scale-95"
                >
                  <Camera className="w-4 h-4" />
                </button>
                <input
                  ref={fileInputRef}
                  type="file"
                  accept="image/*"
                  onChange={handleImageUpload}
                  className="hidden"
                />
              </div>
              <div className="pb-2">
                <h2 className="text-3xl font-bold text-white drop-shadow-md">{formData.name}</h2>
                <p className="text-white/90 font-medium capitalize">{user?.role} • {user?.id}</p>
              </div>
            </div>
          </div>

          <CardContent className="pt-20 space-y-8">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6 pt-4">
              <div className="space-y-4">
                <div className="space-y-2">
                  <Label htmlFor="name">Full Name</Label>
                  <Input
                    id="name"
                    value={formData.name}
                    onChange={(e) => setFormData({ ...formData, name: e.target.value })}
                  />
                </div>

                <div className="space-y-2">
                  <Label htmlFor="email">Email</Label>
                  <Input
                    id="email"
                    type="email"
                    value={formData.email}
                    onChange={(e) => setFormData({ ...formData, email: e.target.value })}
                  />
                </div>
              </div>

              <div className="space-y-4">
                {user?.role === 'student' && (
                  <>
                    <div className="space-y-2">
                      <Label htmlFor="program">Program</Label>
                      <Input
                        id="program"
                        value={formData.program}
                        onChange={(e) => setFormData({ ...formData, program: e.target.value })}
                      />
                    </div>

                    <div className="space-y-2">
                      <Label htmlFor="year">Year Level</Label>
                      <Select
                        value={formData.year.toString()}
                        onValueChange={(value) => setFormData({ ...formData, year: parseInt(value) })}
                      >
                        <SelectTrigger>
                          <SelectValue placeholder="Select year" />
                        </SelectTrigger>
                        <SelectContent>
                          <SelectItem value="1">1st Year</SelectItem>
                          <SelectItem value="2">2nd Year</SelectItem>
                          <SelectItem value="3">3rd Year</SelectItem>
                          <SelectItem value="4">4th Year</SelectItem>
                        </SelectContent>
                      </Select>
                    </div>
                  </>
                )}
                
                <div className="space-y-2">
                  <Label htmlFor="id">ID Number</Label>
                  <Input
                    id="id"
                    value={user?.id}
                    disabled
                    className="bg-accent/50"
                  />
                </div>
              </div>
            </div>

            <div className="flex justify-end gap-3 pt-6 border-t">
              <Button variant="outline" onClick={onBack} className="px-8 rounded-full">
                Cancel
              </Button>
              <Button 
                onClick={handleSave}
                className="bg-primary hover:bg-primary/90 text-white font-bold px-8 rounded-full shadow-lg shadow-primary/20"
              >
                <Save className="w-4 h-4 mr-2" />
                Save Changes
              </Button>
            </div>
          </CardContent>
        </Card>
      </main>
    </div>
  );
}
