'use client';

import { useState, useEffect } from 'react';
import { useAuth } from '@/contexts/AuthContext';
import { getSubjectsAction, getEnrollmentsAction } from '@/app/actions/dbActions';
import { Subject, Enrollment } from '@/utils/storage';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { BookOpen, Calendar, LogOut, UserCircle, School } from 'lucide-react';
import EnrollSubjectDialog from './EnrollSubjectDialog';
import StudentCalendar from './StudentCalendar';
import SubjectDetailsStudent from './SubjectDetailsStudent';
import ProfilePage from '../profile/ProfilePage';

export default function StudentDashboard() {
  const { user, logout } = useAuth();
  const [enrolledSubjects, setEnrolledSubjects] = useState<Subject[]>([]);
  const [selectedSubject, setSelectedSubject] = useState<Subject | null>(null);
  const [activeTab, setActiveTab] = useState('dashboard');
  const [showProfile, setShowProfile] = useState(false);

  useEffect(() => {
    loadData();
  }, [user]);

  const loadData = async () => {
    if (!user) return;
    const enrollments = await getEnrollmentsAction();
    const subjects = await getSubjectsAction();
    
    const myEnrollments = enrollments.filter(e => 
      e.studentId === user.id && e.status === 'approved'
    );
    const mySubjects = subjects.filter(s => 
      myEnrollments.some(e => e.subjectId === s.id)
    );
    
    setEnrolledSubjects(mySubjects);
  };

  if (showProfile) {
    return <ProfilePage onBack={() => setShowProfile(false)} />;
  }

  if (selectedSubject) {
    return (
      <SubjectDetailsStudent 
        subject={selectedSubject} 
        onBack={() => setSelectedSubject(null)} 
      />
    );
  }

  return (
    <div className="min-h-screen bg-muted/20">
      <header className="bg-white border-b sticky top-0 z-10 shadow-sm">
        <div className="container mx-auto px-6 py-5 flex items-center justify-between">
          <div className="flex items-center gap-4">
            <div className="w-14 h-14 rounded-2xl flex items-center justify-center bg-primary shadow-xl shadow-primary/20">
              <School className="text-white h-8 w-8" />
            </div>
            <div>
              <h1 className="text-2xl font-black text-primary leading-none">Student Portal</h1>
              <p className="text-[10px] uppercase font-black text-muted-foreground tracking-[0.3em] mt-1">{user?.name}</p>
            </div>
          </div>
          <div className="flex items-center gap-3">
            <Button variant="outline" onClick={() => setShowProfile(true)} className="hover:text-primary hover:bg-primary/5 border-primary/20 h-12 px-6 rounded-2xl font-black text-xs uppercase tracking-widest">
              <UserCircle className="w-4 h-4 mr-2" />
              Profile
            </Button>
            <Button variant="outline" onClick={logout} className="hover:text-primary hover:bg-primary/5 border-primary/20 h-12 px-6 rounded-2xl font-black text-xs uppercase tracking-widest">
              <LogOut className="w-4 h-4 mr-2" />
              Logout
            </Button>
          </div>
        </div>
      </header>

      <main className="container mx-auto px-6 py-10 max-w-7xl">
        <div className="mb-12 flex flex-col md:flex-row md:items-end justify-between gap-8">
          <div>
            <h2 className="text-5xl font-black tracking-tighter mb-2">Academic Roadmap</h2>
            <p className="text-muted-foreground font-bold uppercase tracking-widest text-[10px] mt-1 italic">Welcome back to your personalized learning dashboard</p>
          </div>
          <EnrollSubjectDialog onEnrolled={loadData} />
        </div>

        <Tabs value={activeTab} onValueChange={setActiveTab}>
          <TabsList className="grid w-full grid-cols-2 mb-12 max-w-md bg-white border border-primary/10 h-16 p-1.5 rounded-[1.5rem] shadow-sm">
            <TabsTrigger value="dashboard" className="rounded-xl font-black uppercase text-[10px] tracking-widest data-[state=active]:bg-primary data-[state=active]:text-white">
              <BookOpen className="w-4 h-4 mr-2" />
              My Subjects
            </TabsTrigger>
            <TabsTrigger value="calendar" className="rounded-xl font-black uppercase text-[10px] tracking-widest data-[state=active]:bg-primary data-[state=active]:text-white">
              <Calendar className="w-4 h-4 mr-2" />
              Weekly Schedule
            </TabsTrigger>
          </TabsList>

          <TabsContent value="dashboard" className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
              {enrolledSubjects.map((subject) => (
                <Card 
                  key={subject.id} 
                  className="cursor-pointer hover:shadow-2xl transition-all border-primary/5 hover:border-primary/20 group relative overflow-hidden h-full flex flex-col rounded-[2.5rem]"
                  onClick={() => setSelectedSubject(subject)}
                >
                  <div className="h-3 bg-primary w-full" />
                  <CardHeader className="p-8 pb-4">
                    <CardTitle className="text-2xl font-black group-hover:text-primary transition-colors tracking-tight">{subject.name}</CardTitle>
                    <CardDescription className="font-black flex items-center gap-2 text-muted-foreground uppercase text-[10px] tracking-widest mt-2">
                      <Calendar className="h-3 w-3 text-primary" /> {subject.day} <span className="text-primary">•</span> {subject.time}
                    </CardDescription>
                  </CardHeader>
                  <CardContent className="p-8 pt-4 flex-1 flex flex-col justify-end">
                    <div className="pt-6 border-t border-primary/5 mt-auto">
                      <p className="text-[10px] font-black uppercase text-muted-foreground tracking-widest mb-2">Authorized Faculty</p>
                      <span className="font-black text-xl">{subject.teacherName}</span>
                    </div>
                  </CardContent>
                </Card>
              ))}
              
              {enrolledSubjects.length === 0 && (
                <Card className="col-span-full border-dashed border-4 border-primary/10 bg-primary/5 rounded-[2.5rem]">
                  <CardContent className="flex flex-col items-center justify-center py-24">
                    <BookOpen className="w-20 h-20 text-primary/20 mb-6" />
                    <h3 className="text-2xl font-black mb-2">Registry Empty</h3>
                    <p className="text-muted-foreground font-bold uppercase tracking-widest text-xs text-center max-w-sm">Ready to begin your academic session? Click the enrollment button to secure your classes.</p>
                  </CardContent>
                </Card>
              )}
            </div>
          </TabsContent>

          <TabsContent value="calendar" className="animate-in fade-in slide-in-from-bottom-4 duration-500">
            <StudentCalendar subjects={enrolledSubjects} />
          </TabsContent>
        </Tabs>
      </main>
    </div>
  );
}