'use client';

import { useState, useEffect } from 'react';
import { useAuth } from '@/contexts/AuthContext';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { Users, BookOpen, LogOut, GraduationCap, School, ShieldAlert } from 'lucide-react';
import { getUsersAction, getSubjectsAction, getEnrollmentsAction } from '@/app/actions/dbActions';
import { User, Subject, Enrollment } from '@/utils/storage';

export default function AdminDashboard() {
  const { logout } = useAuth();
  const [teachers, setTeachers] = useState<User[]>([]);
  const [students, setStudents] = useState<User[]>([]);
  const [subjects, setSubjects] = useState<Subject[]>([]);
  const [enrollments, setEnrollments] = useState<Enrollment[]>([]);
  const [selectedTeacher, setSelectedTeacher] = useState<User | null>(null);
  const [activeTab, setActiveTab] = useState('overview');

  useEffect(() => {
    loadData();
  }, []);

  const loadData = async () => {
    const users = await getUsersAction();
    const allSubjects = await getSubjectsAction();
    const allEnrollments = await getEnrollmentsAction();
    
    setTeachers(users.filter(u => u.role === 'teacher'));
    setStudents(users.filter(u => u.role === 'student'));
    setSubjects(allSubjects);
    setEnrollments(allEnrollments);
  };

  const getSubjectsByTeacher = (teacherId: string) => {
    return subjects.filter(s => s.teacherId === teacherId);
  };

  const getEnrollmentCount = (subjectId: string) => {
    return enrollments.filter(e => e.subjectId === subjectId && e.status === 'approved').length;
  };

  return (
    <div className="min-h-screen bg-muted/20">
      <header className="bg-white border-b sticky top-0 z-10 shadow-sm">
        <div className="container mx-auto px-6 py-5 flex items-center justify-between">
          <div className="flex items-center gap-4">
            <div className="w-14 h-14 rounded-2xl flex items-center justify-center bg-primary shadow-xl shadow-primary/20">
              <ShieldAlert className="text-white h-8 w-8" />
            </div>
            <div>
              <h1 className="text-2xl font-black text-primary leading-none">Admin Console</h1>
              <p className="text-[10px] uppercase font-black text-muted-foreground tracking-[0.3em] mt-1">System Oversight v1.0</p>
            </div>
          </div>
          <Button variant="outline" onClick={logout} className="hover:text-primary hover:bg-primary/5 border-primary/20 h-12 px-6 rounded-2xl font-black text-xs uppercase tracking-widest">
            <LogOut className="w-4 h-4 mr-2" />
            Terminate Session
          </Button>
        </div>
      </header>

      <main className="container mx-auto px-6 py-10 max-w-7xl">
        <Tabs value={activeTab} onValueChange={setActiveTab}>
          <TabsList className="grid w-full grid-cols-3 mb-12 max-w-3xl bg-white border border-primary/10 h-16 p-1.5 rounded-[1.5rem] shadow-sm">
            <TabsTrigger value="overview" className="rounded-xl font-black uppercase text-[10px] tracking-widest data-[state=active]:bg-primary data-[state=active]:text-white">
              <BookOpen className="w-4 h-4 mr-2" />
              Overview
            </TabsTrigger>
            <TabsTrigger value="teachers" className="rounded-xl font-black uppercase text-[10px] tracking-widest data-[state=active]:bg-primary data-[state=active]:text-white">
              <GraduationCap className="w-4 h-4 mr-2" />
              Teaching Staff
            </TabsTrigger>
            <TabsTrigger value="students" className="rounded-xl font-black uppercase text-[10px] tracking-widest data-[state=active]:bg-primary data-[state=active]:text-white">
              <Users className="w-4 h-4 mr-2" />
              Student Body
            </TabsTrigger>
          </TabsList>

          <TabsContent value="overview" className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
            <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
              {[
                { label: 'Teachers', count: teachers.length, icon: GraduationCap, color: 'bg-primary' },
                { label: 'Students', count: students.length, icon: Users, color: 'bg-blue-600' },
                { label: 'Subjects', count: subjects.length, icon: BookOpen, color: 'bg-green-600' }
              ].map((stat) => (
                <Card key={stat.label} className="border-primary/5 hover:border-primary/20 transition-all shadow-xl rounded-[2rem] overflow-hidden">
                  <CardContent className="p-8">
                    <div className="flex items-center justify-between mb-4">
                      <div className={`${stat.color} p-3 rounded-2xl text-white shadow-lg`}>
                        <stat.icon className="w-6 h-6" />
                      </div>
                      <span className="text-[10px] font-black uppercase tracking-widest text-muted-foreground">Active Units</span>
                    </div>
                    <p className="text-5xl font-black text-primary">{stat.count}</p>
                    <p className="text-xs font-black text-muted-foreground mt-2 uppercase tracking-widest">Registered {stat.label}</p>
                  </CardContent>
                </Card>
              ))}
            </div>

            <Card className="border-primary/5 shadow-2xl rounded-[2.5rem] overflow-hidden">
              <CardHeader className="bg-primary/5 border-b border-primary/10 p-10">
                <CardTitle className="text-2xl font-black">Subject Master List</CardTitle>
                <CardDescription className="font-bold text-muted-foreground uppercase tracking-widest text-[10px] mt-1">Cross-system academic session audit</CardDescription>
              </CardHeader>
              <CardContent className="p-10">
                {subjects.length === 0 ? (
                  <div className="text-center py-20 bg-muted/20 rounded-[2rem] border-4 border-dashed border-primary/10">
                    <BookOpen className="h-16 w-16 text-primary/20 mx-auto mb-4" />
                    <p className="text-muted-foreground font-black uppercase tracking-widest text-xs">No entries found in master records</p>
                  </div>
                ) : (
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                    {subjects.map((subject) => (
                      <div key={subject.id} className="p-8 border border-primary/5 rounded-[2rem] hover:bg-primary/5 transition-all group shadow-sm bg-white">
                        <div className="flex items-start justify-between">
                          <div className="flex-1">
                            <h4 className="font-black text-2xl group-hover:text-primary transition-colors tracking-tighter">{subject.name}</h4>
                            <div className="space-y-2 mt-4">
                              <p className="text-xs font-black text-muted-foreground flex items-center gap-3 uppercase tracking-widest">
                                <GraduationCap className="h-4 w-4 text-primary" /> {subject.teacherName}
                              </p>
                              <p className="text-xs font-black text-muted-foreground flex items-center gap-3 uppercase tracking-widest">
                                <School className="h-4 w-4 text-primary" /> {subject.day} • {subject.time}
                              </p>
                            </div>
                          </div>
                          <div className="text-right">
                            <p className="text-[9px] font-black uppercase tracking-[0.2em] text-muted-foreground mb-1">Census</p>
                            <p className="text-4xl font-black text-primary leading-none">{getEnrollmentCount(subject.id)}</p>
                          </div>
                        </div>
                      </div>
                    ))}
                  </div>
                )}
              </CardContent>
            </Card>
          </TabsContent>

          <TabsContent value="teachers" className="space-y-8">
            <div className="flex items-center justify-between mb-6">
              <div>
                <h2 className="text-4xl font-black tracking-tighter">Academic Staff</h2>
                <p className="text-muted-foreground font-bold uppercase tracking-widest text-[10px] mt-1">Personnel Directory</p>
              </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
              {teachers.map((teacher) => (
                <Card 
                  key={teacher.id}
                  className="hover:shadow-2xl transition-all border-primary/5 group overflow-hidden rounded-[2.5rem]"
                >
                  <div className="h-3 bg-primary w-full" />
                  <CardContent className="p-10 text-center">
                    <div className="flex flex-col items-center space-y-6">
                      <div className="w-28 h-28 rounded-[2rem] bg-primary/10 flex items-center justify-center border-4 border-white shadow-xl rotate-3 group-hover:rotate-0 transition-all overflow-hidden">
                        {teacher.profilePic ? (
                          <img src={teacher.profilePic} alt={teacher.name} className="w-full h-full object-cover" />
                        ) : (
                          <GraduationCap className="w-14 h-14 text-primary" />
                        )}
                      </div>
                      <div>
                        <p className="font-black text-2xl group-hover:text-primary transition-colors tracking-tighter">{teacher.name}</p>
                        <p className="text-xs font-black text-muted-foreground uppercase tracking-[0.2em] mt-2">ID: {teacher.id}</p>
                      </div>
                      <div className="pt-6 border-t border-primary/5 w-full flex justify-between items-center px-4">
                        <span className="text-[10px] font-black text-muted-foreground uppercase tracking-widest">Load</span>
                        <span className="font-black text-xl text-primary">{getSubjectsByTeacher(teacher.id).length} Subjects</span>
                      </div>
                    </div>
                  </CardContent>
                </Card>
              ))}
            </div>
          </TabsContent>

          <TabsContent value="students" className="space-y-8">
            <div className="flex items-center justify-between mb-6">
              <div>
                <h2 className="text-4xl font-black tracking-tighter">Student Registry</h2>
                <p className="text-muted-foreground font-bold uppercase tracking-widest text-[10px] mt-1">Enrolled Population</p>
              </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
              {students.map((student) => {
                const myEnrollments = enrollments.filter(e => e.studentId === student.id && e.status === 'approved');
                return (
                  <Card key={student.id} className="border-primary/5 shadow-xl hover:shadow-2xl transition-all rounded-[2.5rem] overflow-hidden">
                    <CardContent className="p-10 text-center">
                      <div className="flex flex-col items-center space-y-6">
                        <div className="w-28 h-28 rounded-[2rem] bg-primary/10 flex items-center justify-center border-4 border-white shadow-xl -rotate-3 hover:rotate-0 transition-all overflow-hidden">
                          {student.profilePic ? (
                            <img src={student.profilePic} alt={student.name} className="w-full h-full object-cover" />
                          ) : (
                            <Users className="w-14 h-14 text-primary" />
                          )}
                        </div>
                        <div>
                          <p className="font-black text-2xl tracking-tighter">{student.name}</p>
                          <p className="text-xs font-black text-muted-foreground uppercase tracking-[0.2em] mt-2">ID: {student.id}</p>
                          <div className="flex gap-2 justify-center mt-4">
                            <span className="bg-primary text-white text-[9px] font-black px-4 py-1.5 rounded-full uppercase tracking-widest">{student.program}</span>
                            <span className="bg-muted text-muted-foreground text-[9px] font-black px-4 py-1.5 rounded-full uppercase tracking-widest">Year {student.year}</span>
                          </div>
                        </div>
                        <div className="pt-6 border-t border-primary/5 w-full flex justify-between items-center px-4">
                          <span className="text-[10px] font-black text-muted-foreground uppercase tracking-widest">Class Count</span>
                          <span className="font-black text-xl text-primary">{myEnrollments.length}</span>
                        </div>
                      </div>
                    </CardContent>
                  </Card>
                );
              })}
            </div>
          </TabsContent>
        </Tabs>
      </main>
    </div>
  );
}